const express = require('express');
const bodyParser = require('body-parser');
const redis = require('redis');
const crypto = require('crypto');
const jwt = require('jsonwebtoken');
const { body, validationResult } = require('express-validator');

const app = express();
const redisClient = redis.createClient();
const PORT = process.env.PORT || 3000;
const JWT_SECRET = process.env.JWT_SECRET || 'your_jwt_secret';
const REFRESH_TOKEN_EXPIRY = 365 * 24 * 60 * 60; // 1 year in seconds

app.use(bodyParser.json());

redisClient.on('error', (err) => {
    console.error('Redis error:', err);
});

app.post('/token', 
    body('username').isString().notEmpty(),
    body('password').isString().notEmpty(),
    (req, res) => {
        const errors = validationResult(req);
        if (!errors.isEmpty()) {
            return res.status(400).json({ errors: errors.array() });
        }

        const { username, password } = req.body;

        // Validate user credentials (implement your own user validation)
        if (username === 'validUser' && password === 'validPassword') {
            const refreshToken = crypto.randomBytes(64).toString('hex');
            const userId = 'user_id'; // Replace with actual user ID

            redisClient.setex(refreshToken, REFRESH_TOKEN_EXPIRY, userId, (err) => {
                if (err) {
                    return res.status(500).json({ error: 'Internal Server Error' });
                }
                res.json({ refreshToken });
            });
        } else {
            res.status(401).json({ error: 'Invalid credentials' });
        }
    }
);

app.post('/refresh', 
    body('refreshToken').isString().notEmpty(),
    (req, res) => {
        const errors = validationResult(req);
        if (!errors.isEmpty()) {
            return res.status(400).json({ errors: errors.array() });
        }

        const { refreshToken } = req.body;

        redisClient.get(refreshToken, (err, userId) => {
            if (err || !userId) {
                return res.status(403).json({ error: 'Invalid refresh token' });
            }

            const newAccessToken = jwt.sign({ userId }, JWT_SECRET, { expiresIn: '15m' });
            res.json({ accessToken: newAccessToken });
        });
    }
);

app.listen(PORT, () => {
    console.log(`OAuth 2.0 Authorization Server running on port ${PORT}`);
});